function makeWavePath(x, y, width, height) {
  const left = x - 14;
  const right = x + width + 14;
  const top = y + height * 0.42;
  const bottom = y + height + 36;
  const step = (right - left) / 4;

  return [
    `M ${left} ${bottom}`,
    `L ${left} ${top}`,
    `C ${left + step * 0.5} ${top - 12}, ${left + step * 0.5} ${top + 15}, ${left + step} ${top + 5}`,
    `S ${left + step * 1.5} ${top - 10}, ${left + step * 2} ${top + 3}`,
    `S ${left + step * 2.5} ${top + 16}, ${left + step * 3} ${top + 2}`,
    `S ${left + step * 3.5} ${top - 9}, ${right} ${top + 5}`,
    `L ${right} ${bottom}`,
    "Z",
  ].join(" ");
}

export default function PTSLongStatusLogo({ status, label = "PTS" }) {
  const phase = status?.phase || "idle";
  const ids = useId().replace(/:/g, "");
  const isLoading = phase === "loading";
  const isSuccess = phase === "success";
  const isError = phase === "error";
  const flashColor = isSuccess ? "#2EC4B6" : isError ? "#F64258" : null;

  return (
    <span
      className={`pts-long-status-logo${isLoading ? " is-loading" : ""}${isSuccess ? " is-success" : ""}${isError ? " is-error" : ""}`}
      title={label}
      aria-label={label}
    >
      <img src={ptsLongLogo} alt="PTS logo" className="pts-long-status-logo__base" />

      <svg
        className="pts-long-status-logo__overlay"
        viewBox="0 0 1411 214"
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden="true"
        preserveAspectRatio="xMidYMid meet"
      >
        <defs>
          {SEGMENTS.map((segment) => (
            <clipPath id={`${ids}-${segment.key}-clip`} key={segment.key}>
              <path d={segment.fillPath} />
            </clipPath>
          ))}
        </defs>

        {SEGMENTS.map((segment) => {
          const wavePath = makeWavePath(
            segment.fluidBox.x,
            segment.fluidBox.y,
            segment.fluidBox.width,
            segment.fluidBox.height
          );
          const liquidColor = flashColor || segment.baseColor;

          return (
            <g
              key={segment.key}
              clipPath={`url(#${ids}-${segment.key}-clip)`}
              className="pts-long-status-logo__liquid-clip"
            >
              <g className="pts-long-status-logo__liquid">
                <rect
                  x={segment.fluidBox.x - 18}
                  y={segment.fluidBox.y + 10}
                  width={segment.fluidBox.width + 36}
                  height={segment.fluidBox.height + 42}
                  fill={liquidColor}
                  opacity="0.68"
                />
                <path
                  d={wavePath}
                  fill="rgba(255,255,255,0.36)"
                  className="pts-long-status-logo__wave"
                />
                <path
                  d={wavePath}
                  fill={liquidColor}
                  opacity="0.78"
                  className="pts-long-status-logo__wave pts-long-status-logo__wave--color"
                />
              </g>
            </g>
          );
        })}
      </svg>

      <span
        className="pts-long-status-logo__flash"
        style={
          flashColor
            ? {
                backgroundColor: flashColor,
                WebkitMaskImage: `url(${ptsLongLogo})`,
                maskImage: `url(${ptsLongLogo})`,
              }
            : undefined
        }
      />
    </span>
  );
}
